<section class="auth-shell container"><div class="auth-card"><span class="eyebrow">A faster next order</span><h1>Create your account</h1><p>Save order history and contact information.</p><form method="post" class="form-stack"><?= csrf_field() ?><label class="form-honeypot" aria-hidden="true">Website<input name="website" tabindex="-1" autocomplete="off"></label><label>Full name<input name="name" autocomplete="name" required maxlength="120"></label><label>Email<input type="email" name="email" autocomplete="email" required maxlength="254"></label><label>Phone<input type="tel" name="phone" autocomplete="tel" maxlength="40"></label><label>Password <small>At least 10 characters</small><input type="password" name="password" minlength="10" maxlength="200" autocomplete="new-password" required></label><button class="button button-primary button-wide" type="submit">Create account<i data-lucide="user-plus"></i></button></form><p class="form-foot">Already registered? <a href="<?= url('login') ?>">Sign in</a></p></div></section>
